INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-6f0ba476-moex-00294', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於「繳納稅捐期間」，下列敘述何者錯誤？', '["因天災、事變而遲誤依法所定繳納稅捐期間者，該管稅捐稽徵機關，得視實際情形，延長其繳納期 間，並公告之", "納稅義務人因天災、事變、不可抗力之事由或為經濟弱勢者，不能於法定期間內繳清稅捐者，得於 規定納稅期間內，向稅捐稽徵機關申請延期或分期繳納，其延期或分期繳納之期間，不得逾3年", "納稅義務人依法應繳納所得稅，因客觀事實發生財務困難，不能於法定期間內繳清稅捐者，得於規 定納稅期限內，向稅捐稽徵機關申請分期繳納", "納稅義務人對核准分期繳納之任何一期應繳稅捐，未如期繳納者，稅捐稽徵機關不得於該期繳納期 間屆滿之翌日起3日內，就未繳清之餘額稅款，發單通知納稅義務人，限10日內一次全部繳清"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00295', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於「稅捐之核課期間」，下列敘述何者錯誤？', '["依法應由納稅義務人申報繳納之稅捐，已在規定期間內申報，且無故意以詐欺或其他不正當方法逃 漏稅捐者，其核課期間為5年", "未於規定期間內申報，或故意以詐欺或其他不正當方法逃漏稅捐者，其核課期間為7年", "稅捐之核課期間屆滿時，納稅義務人對核定稅捐處分提起行政救濟尚未終結者，自核定稅捐處分經 訴願或行政訴訟撤銷須另為處分確定之日起算1年內，其時效不完成", "稅捐之核課期間，適用行政程序法第131條第3項至第134條有關時效中斷之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00296', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '根據稅捐稽徵法規定，下列敘述何者錯誤？', '["財政部依稅捐稽徵法或稅法所發布之解釋函令，對於據以申請之案件發生效力。但有利於納稅義務 人者，對於尚未核課確定之案件適用之", "財政部得本互惠原則，與外國政府或國際組織商訂稅務用途資訊交換及相互提供其他稅務協助之 條約或協定，於報經行政院核准後，以外交換文方式行之", "稅捐稽徵法所稱相當擔保，係指相當於擔保稅款之擔保品，例如面額等於擔保稅款數額之上櫃之有 價證券", "稅捐稽徵機關對於按納稅義務人申報資料核定之案件，得以公告方式，載明申報業經核定，代替核 定稅額通知書之填具及送達。但各稅法另有規定者，從其規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00297', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '有關稅捐稽徵法規定，下列敘述何者錯誤？', '["因適用法令、認定事實、計算或其他原因之錯誤，致溢繳稅款者，納稅義務人僅得自繳納之日起5 年內提出具體證明，申請退還", "稅捐之徵收，優先於普通債權", "破產財團成立後，其應納稅捐為財團費用，由破產管理人依破產法之規定清償之", "公司重整中所發生之稅捐，為公司重整債務，依公司法之規定清償之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00298', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於所得基本稅額條例，下列敘述何者錯誤？', '["營利事業或個人依所得基本稅額條例規定計算之一般所得稅額高於或等於基本稅額者，其應繳納 之所得稅，應按所得稅法及其他相關法律規定計算認定之", "營利事業或個人依所得基本稅額條例規定計算之一般所得稅額低於基本稅額者，其應繳納之所得 稅，除按所得稅法及其他相關法律計算認定外，應另就基本稅額與一般所得稅額之差額認定之", "基本稅額與一般所得稅額之差額，不得以其他法律規定之投資抵減稅額減除", "營利事業或個人與國內外其他個人或營利事業、教育、文化、公益、慈善機關或團體相互間，如有 藉資金、股權之移轉或其他虛偽之安排，不當為他人或自己規避或減少納稅義務者，稽徵機關得依 查得資料調整，不必報經財政部核准"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00299', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，下列敘述何者錯誤？', '["個人交易中華民國105年1月1日以後取得預售屋及其坐落基地，其交易所得應於每年5月辦理 結算申報", "非中華民國境內居住之個人，於一課稅年度內在中華民國境內居留合計不超過90天者，其自中華 民國境外僱主所取得之勞務報酬，無須計入中華民國來源所得", "所得稅法第88條各類所得稅款之扣繳義務人，應於每月10日前將上1月內所扣稅款向國庫繳清", "委託人為營利事業之信託契約，信託成立時，明定信託利益之全部或一部之受益人為非委託人者， 該受益人應將享有信託利益之權利價值，併入成立年度之所得額，依所得稅法規定課徵所得稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00300', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '下列何種所得免納所得稅？', '["各級政府機關取得之各種所得", "取自營利事業贈與之財產", "政府舉辦之獎券中獎獎金", "自力耕作之所得"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00301', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於所得稅法第43條之3之規定，下列何者錯誤？', '["營利事業及其關係人直接或間接持有在中華民國境外低稅負國家或地區之關係企業股份或資本額 合計達百分之五十以上或對該關係企業具有重大影響力者，除符合該條第1項各款規定之一者外， 營利事業應將該關係企業當年度之盈餘，按其持有該關係企業股份或資本額之比率及持有期間計 算，認列投資收益，計入當年度所得額課稅", "該條所稱低稅負國家或地區，指關係企業所在國家或地區，其營利事業所得稅或實質類似租稅之稅 率未逾所得稅法第5條第5項第2款所定稅率之百分之七十或僅對其境內來源所得課稅者", "關係企業自符合該條第 1 項規定之當年度起，其各期虧損經所在國家或地區或中華民國合格會計 師查核簽證，並由營利事業依規定格式填報及經所在地稽徵機關核定者，得於虧損發生年度之次年 度起3年內自該關係企業盈餘中扣除，依第1項規定計算該營利事業投資收益", "營利事業於實際獲配該關係企業股利或盈餘時，在已依該條第 1 項規定認列投資收益範圍內，不 計入所得額課稅；超過已認列投資收益部分，應於獲配年度計入所得額課稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00302', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於所得稅法「暫繳」之規定，下列敘述何者錯誤？', '["營利事業除符合所得稅法第69條規定者外，應於每年9月1日起至9月30日止，按其上年度結 算申報營利事業所得稅應納稅額之二分之一為暫繳稅額，自行向庫繳納，並依規定格式，填具暫繳 稅額申報書，檢附暫繳稅額繳款收據，一併向該管稽徵機關申報", "公司組織之營利事業，會計帳冊簿據完備，使用所得稅法第77條所稱藍色申報書或經會計師查核 簽證，並如期辦理暫繳申報者，得以當年度前6個月之營業收入總額，依本法有關營利事業所得稅 之規定，試算其前半年之營利事業所得額，按當年度稅率，計算其暫繳稅額，不適用所得稅法第67 條第1項暫繳稅額之計算方式", "營利事業未依所得稅法第67條第1項規定期間辦理暫繳，而於10月31日以前已依該條第1項規 定計算補報及補繳暫繳稅額者，應自10月1日起至其繳納暫繳稅額之日止，按其暫繳稅額，依第 123條規定之存款利率，按日加計利息，一併徵收", "營利事業逾10月31日仍未依第68條第1項規定辦理暫繳者，稽徵機關應按所得稅法第67條第 1項規定計算其暫繳稅額，並依同法第123條規定之存款利率，加計1個月之利息，一併填具暫繳 稅額核定通知書，通知該營利事業於1個月內自行向庫繳納"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00303', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依遺產及贈與稅法規定，下列敘述何者錯誤？', '["被繼承人死亡遺有財產者，納稅義務人應於被繼承人死亡之日起 6 個月內，向戶籍所在地主管稽 徵機關依遺產及贈與稅法規定辦理遺產稅申報", "非中華民國國民死亡時在中華民國境內遺有財產者，納稅義務人應向中華民國中央政府所在地之 主管稽徵機關辦理遺產稅申報", "除遺產及贈與稅法第20條所規定之贈與外，贈與人在1年內贈與他人之財產總值超過贈與稅免稅 額時，應於超過免稅額之贈與行為發生後60日內，向主管稽徵機關依該法規定辦理贈與稅申報", "同一贈與人在同 1 年內有兩次以上依遺產及贈與稅法規定應申報納稅之贈與行為者，應於辦理後 一次贈與稅申報時，將同1年內以前各次之贈與事實及納稅情形合併申報"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
